/*
======================================================================
Design System
======================================================================
*/

:root {
    /* Brand & core colors (from provided palette and visual sampling) */
    --color-primary-red: #C03030;        /* Accent red used for highlights */
    --color-primary-text: #444444;       /* Main text / heading color */
    --color-secondary-text: #777777;     /* Muted text */
    --color-page-bg: #F2F2F2;            /* Overall page background */
    --color-surface: #FFFFFF;            /* Card / content background */
    --color-border: #CCCCCC;             /* Default border */
    --color-header-bg: #F5F5F5;          /* Light grey header bar */
    --color-header-divider-top: #3F3F3F; /* Dark band below header */
    --color-header-divider-bottom: #2F2F2F;
    --color-footer-bg: #F5F5F5;          /* Main footer background */
    --color-footer-bottom-bg: #3F3F3F;   /* Dark footer strip */
    --color-footer-bottom-text: #EDEDED; /* Text on dark footer strip */

    /* Semantic colors (from brief) */
    --color-success: #2E7D32;
    --color-error: #C62828;
    --color-warning: #ED6C02;
    --color-info: #1565C0;

    /* Typography */
    --font-heading: "DM Sans", Helvetica, Arial, sans-serif;
    --font-body: "Source Sans 3", Arial, sans-serif;
    --font-code: "Source Code Pro", Menlo, Monaco, Consolas, "Courier New", monospace;

    --font-size-root: 15px;    /* Base size, between 14–16px */
    --font-size-body: 1rem;    /* 15px */
    --font-size-small: 0.8rem; /* ~12px */
    --font-size-h1: 1.9rem;    /* ~28–29px */
    --font-size-h2: 1.6rem;    /* ~24px */
    --font-size-h3: 1.25rem;   /* ~19–20px */

    --line-height-tight: 1.2;
    --line-height-normal: 1.45;
    --line-height-relaxed: 1.7;

    /* Spacing scale (8px base) */
    --space-xxs: 0.25rem;  /* 4px */
    --space-xs: 0.5rem;    /* 8px */
    --space-sm: 1rem;      /* 16px */
    --space-md: 1.5rem;    /* 24px */
    --space-lg: 2rem;      /* 32px */
    --space-xl: 3rem;      /* 48px */
    --space-xxl: 4rem;     /* 64px */

    /* Radii */
    --radius-input: 4px;    /* Slight rounding for inputs/buttons */
    --radius-button: 3px;

    /* Layout */
    --container-max-width: 1040px;
}

/*
======================================================================
Global Resets & Base Styles
======================================================================
*/

*, *::before, *::after {
    box-sizing: border-box;
}

html {
    font-size: var(--font-size-root);
}

body {
    margin: 0;
    padding: 0;
    background-color: var(--color-page-bg);
    color: var(--color-primary-text);
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-relaxed);
}

img {
    max-width: 100%;
    height: auto;
    border: 0;
}

a {
    color: var(--color-primary-red);
    text-decoration: none;
}

a:hover,
 a:focus {
    text-decoration: underline;
}

p {
    margin: 0 0 var(--space-sm);
}

h1, h2, h3, h4, h5, h6 {
    margin: 0 0 var(--space-sm);
    font-family: var(--font-heading);
    font-weight: 600;
    line-height: var(--line-height-tight);
    color: var(--color-primary-text);
}

h1 { font-size: var(--font-size-h1); }

h2 { font-size: var(--font-size-h2); }

h3 { font-size: var(--font-size-h3); }

small {
    font-size: var(--font-size-small);
}

code, pre {
    font-family: var(--font-code);
}

/* Accessible focus outline */
:focus-visible {
    outline: 2px solid var(--color-primary-red);
    outline-offset: 2px;
}

/*
======================================================================
Layout Helpers
======================================================================
*/

.container {
    max-width: var(--container-max-width);
    margin-left: auto;
    margin-right: auto;
    padding-left: var(--space-md);
    padding-right: var(--space-md);
}

.site-content {
    padding-top: var(--space-lg);
    padding-bottom: var(--space-xl);
}

.content-inner {
    background-color: var(--color-surface);
    padding: var(--space-lg);
    box-shadow: 0 0 0 1px rgba(0, 0, 0, 0.03);
}

/*
======================================================================
Header
======================================================================
*/

.site-header {
    background-color: var(--color-header-bg);
    border-bottom: 1px solid var(--color-border);
}

.header-top {
    padding-top: var(--space-md);
    padding-bottom: var(--space-sm);
}

.header-top-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--space-lg);
}

/* Branding */

.site-branding {
    display: flex;
    align-items: center;
}

.brand-icon {
    width: 40px;
    height: 40px;
    border-radius: 4px;
    background: linear-gradient(135deg, #C03030 0, #C03030 40%, #777777 40%, #777777 100%);
    margin-right: var(--space-sm);
}

.brand-text {
    display: flex;
    flex-direction: column;
}

.logo-title {
    font-family: "Georgia", "Times New Roman", serif;
    font-size: 1.7rem; /* Slightly larger, logo-style */
    letter-spacing: 0.06em;
    color: var(--color-primary-text);
}

.logo-subtitle {
    margin-top: 0.1rem;
    font-size: 0.78rem;
    color: var(--color-secondary-text);
}

/* Main navigation */

.main-nav {
    font-family: var(--font-heading);
    font-size: 0.93rem;
}

.main-menu {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    flex-wrap: wrap;
    gap: 0;
}

.menu-item {
    margin-left: var(--space-lg);
}

.menu-item:first-child {
    margin-left: 0;
}

.menu-item a {
    display: block;
    padding: 0.25rem 0;
    color: var(--color-primary-text);
    font-weight: 500;
}

.menu-item a:hover,
.menu-item a:focus {
    color: var(--color-primary-red);
    text-decoration: none;
}

/* Dark dividing band below the header, matching the reference design */

.header-divider {
    height: 18px;
    background-color: var(--color-header-divider-top);
    border-top: 1px solid #4C4C4C;
    border-bottom: 1px solid var(--color-header-divider-bottom);
}

/*
======================================================================
Footer
======================================================================
*/

.site-footer {
    margin-top: var(--space-xl);
    background-color: var(--color-footer-bg);
    border-top: 1px solid var(--color-border);
    font-size: var(--font-size-small);
}

.footer-main {
    padding-top: var(--space-md);
    padding-bottom: var(--space-md);
}

.footer-main-inner {
    display: flex;
    justify-content: center;
}

.footer-nav {
    width: 100%;
}

.footer-links {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    flex-wrap: wrap;
    row-gap: var(--space-xs);
    column-gap: var(--space-lg);
}

.footer-item a {
    color: var(--color-secondary-text);
}

.footer-item a:hover,
.footer-item a:focus {
    color: var(--color-primary-red);
}

.footer-lower {
    background-color: var(--color-footer-bottom-bg);
    color: var(--color-footer-bottom-text);
    padding-top: 0.5rem;
    padding-bottom: 0.5rem;
}

.footer-lower-inner {
    display: flex;
    justify-content: center;
}

.footer-credit {
    margin: 0;
}

/*
======================================================================
Buttons (for potential future forms, matching design system)
======================================================================
*/

button,
input[type="submit"],
input[type="button"] {
    font-family: var(--font-body);
    font-size: 0.93rem;
    line-height: 1.2;
    padding: 0.4rem 0.9rem; /* ~8px x 16px */
    border-radius: var(--radius-button);
    border: 1px solid var(--color-border);
    background-color: #E7E7E7;
    color: var(--color-primary-text);
    cursor: pointer;
}

button:hover,
button:focus,
input[type="submit"]:hover,
input[type="submit"]:focus,
input[type="button"]:hover,
input[type="button"]:focus {
    background-color: #DCDCDC;
}

/*
======================================================================
Form Inputs (for consistency with the flat, utilitarian design)
======================================================================
*/

input[type="text"],
input[type="email"],
input[type="search"],
input[type="password"],
select,
textarea {
    font-family: var(--font-body);
    font-size: 0.93rem;
    padding: 0.4rem 0.5rem;
    border: 1px solid var(--color-border);
    border-radius: var(--radius-input);
    background-color: #FFFFFF;
    color: var(--color-primary-text);
}

label {
    display: block;
    margin-bottom: var(--space-xxs);
    font-size: 0.9rem;
}

.form-field {
    margin-bottom: var(--space-sm);
}

/*
======================================================================
Responsive adjustments
======================================================================
*/

@media (max-width: 800px) {
    .header-top-inner {
        flex-direction: column;
        align-items: flex-start;
    }

    .main-menu {
        flex-wrap: wrap;
    }

    .menu-item {
        margin-left: 0;
        margin-right: var(--space-md);
        margin-bottom: var(--space-xs);
    }

    .content-inner {
        padding: var(--space-md);
    }

    .footer-main-inner {
        justify-content: flex-start;
    }
}

@media (max-width: 500px) {
    .brand-icon {
        display: none; /* Reduce visual clutter on very small screens */
    }

    .logo-title {
        font-size: 1.4rem;
    }
}

/*
======================================================================
Utility Classes (optional, for future use)
======================================================================
*/

.text-muted {
    color: var(--color-secondary-text);
}

.text-center {
    text-align: center;
}

.mt-0 { margin-top: 0 !important; }
.mb-0 { margin-bottom: 0 !important; }
.mb-sm { margin-bottom: var(--space-sm) !important; }
.mb-md { margin-bottom: var(--space-md) !important; }
.mb-lg { margin-bottom: var(--space-lg) !important; }
